import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { 
  Package, 
  TrendingUp, 
  AlertCircle, 
  DollarSign,
  PlusCircle,
  ShoppingCart,
  Users,
  Activity,
  Monitor,
  Smartphone,
  Volume2,
  ChevronDown
} from 'lucide-react';
import { useInventory } from '../contexts/InventoryContext';
import { useAuth } from '../contexts/AuthContext';

const Dashboard = () => {
  const { getStats, items, getCategoryStats } = useInventory();
  const { currentUser } = useAuth();
  const stats = getStats();
  const categoryStats = getCategoryStats();
  const [selectedCategory, setSelectedCategory] = useState('all');

  const recentItems = items.slice(0, 5);
  const lowStockItems = items.filter(item => item.quantity <= 5 && item.quantity > 0);

  const CategoryCard = ({ category, icon: Icon, color, stats, isSelected }) => (
    <Link
      to={`/inventory?category=${category}`}
      className={`card p-6 hover:shadow-xl transition-all duration-300 cursor-pointer ${
        isSelected ? 'ring-2 ring-primary-500 bg-primary-50' : ''
      }`}
      onClick={() => setSelectedCategory(category)}
    >
      <div className="flex items-center justify-between mb-4">
        <div className={`w-12 h-12 rounded-lg flex items-center justify-center ${color}`}>
          <Icon className="w-6 h-6 text-white" />
        </div>
        <ChevronDown className={`w-5 h-5 text-secondary-400 transform transition-transform ${
          isSelected ? 'rotate-180' : ''
        }`} />
      </div>
      <h3 className="text-lg font-semibold text-secondary-900 mb-2">{category}</h3>
      <div className="space-y-1">
        <p className="text-sm text-secondary-600">
          {stats.itemCount} items • {stats.totalQuantity} units
        </p>
        <p className="text-sm font-medium text-primary-600">
          Value: ${stats.totalValue.toFixed(2)}
        </p>
      </div>
    </Link>
  );

  const StockHistogram = () => {
    const maxQuantity = Math.max(...categoryStats.map(stat => stat.totalQuantity));

    return (
      <div className="card p-6">
        <h3 className="text-lg font-semibold text-secondary-900 mb-6">Stock Levels by Category</h3>
        <div className="space-y-4">
          {categoryStats.map((stat) => {
            const percentage = (stat.totalQuantity / maxQuantity) * 100;
            return (
              <div key={stat.category} className="space-y-2">
                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium text-secondary-700">{stat.category}</span>
                  <span className="text-sm text-secondary-600">{stat.totalQuantity} units</span>
                </div>
                <div className="w-full bg-secondary-200 rounded-full h-8 overflow-hidden">
                  <div
                    className="h-full bg-gradient-to-r from-primary-500 to-accent-500 rounded-full flex items-center justify-end pr-3 transition-all duration-500"
                    style={{ width: `${percentage}%` }}
                  >
                    {percentage > 20 && (
                      <span className="text-xs text-white font-medium">
                        {stat.totalQuantity}
                      </span>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const StatCard = ({ title, value, icon: Icon, color, trend }) => (
    <div className="card p-6 hover:shadow-xl transition-shadow duration-300">
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm font-medium text-secondary-600">{title}</p>
          <p className="text-2xl font-bold text-secondary-900 mt-1">{value}</p>
          {trend && (
            <p className={`text-xs mt-2 ${trend > 0 ? 'text-green-600' : 'text-red-600'}`}>
              {trend > 0 ? '+' : ''}{trend}% from last month
            </p>
          )}
        </div>
        <div className={`w-12 h-12 rounded-lg flex items-center justify-center ${color}`}>
          <Icon className="w-6 h-6 text-white" />
        </div>
      </div>
    </div>
  );

  return (
    <div className="animate-fade-in">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-secondary-900">Dashboard</h1>
        <p className="text-secondary-600 mt-2">
          Welcome back, {currentUser?.name}! Here's your inventory overview.
        </p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard
          title="Total Items"
          value={stats.totalItems}
          icon={Package}
          color="bg-primary-500"
          trend={12}
        />
        <StatCard
          title="Total Quantity"
          value={stats.totalQuantity}
          icon={ShoppingCart}
          color="bg-accent-500"
          trend={8}
        />
        <StatCard
          title="Available Items"
          value={stats.availableItems}
          icon={Activity}
          color="bg-green-500"
          trend={5}
        />
        <StatCard
          title="Total Value"
          value={`$${stats.totalValue.toFixed(2)}`}
          icon={DollarSign}
          color="bg-yellow-500"
          trend={15}
        />
      </div>

      {/* Alerts Section */}
      {stats.outOfStock > 0 && (
        <div className="card p-6 mb-8 border-l-4 border-red-500 bg-red-50">
          <div className="flex items-center">
            <AlertCircle className="w-6 h-6 text-red-600 mr-3" />
            <div>
              <h3 className="text-lg font-semibold text-red-800">Low Stock Alert</h3>
              <p className="text-red-600">
                {stats.outOfStock} item{stats.outOfStock > 1 ? 's' : ''} out of stock. 
                {lowStockItems.length > 0 && ` ${lowStockItems.length} item${lowStockItems.length > 1 ? 's' : ''} running low.`}
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Category Cards */}
      <div className="mb-8">
        <h2 className="text-xl font-semibold text-secondary-900 mb-4">Product Categories</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <CategoryCard
            category="Laptops"
            icon={Monitor}
            color="bg-blue-500"
            stats={categoryStats.find(stat => stat.category === 'Laptops')}
            isSelected={selectedCategory === 'Laptops'}
          />
          <CategoryCard
            category="Phones"
            icon={Smartphone}
            color="bg-green-500"
            stats={categoryStats.find(stat => stat.category === 'Phones')}
            isSelected={selectedCategory === 'Phones'}
          />
          <CategoryCard
            category="Speakers"
            icon={Volume2}
            color="bg-purple-500"
            stats={categoryStats.find(stat => stat.category === 'Speakers')}
            isSelected={selectedCategory === 'Speakers'}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Stock Histogram */}
        <StockHistogram />

        {/* Quick Actions */}
        <div className="card">
          <div className="p-6 border-b border-secondary-200">
            <h2 className="text-xl font-semibold text-secondary-900">Quick Actions</h2>
          </div>
          <div className="p-6">
            <div className="grid grid-cols-2 gap-4">
              <Link
                to="/inventory/add"
                className="flex flex-col items-center justify-center p-6 bg-primary-50 rounded-lg hover:bg-primary-100 transition-colors duration-200"
              >
                <PlusCircle className="w-8 h-8 text-primary-600 mb-2" />
                <span className="text-sm font-medium text-primary-700">Add New Item</span>
              </Link>
              <Link
                to="/inventory"
                className="flex flex-col items-center justify-center p-6 bg-accent-50 rounded-lg hover:bg-accent-100 transition-colors duration-200"
              >
                <Package className="w-8 h-8 text-accent-600 mb-2" />
                <span className="text-sm font-medium text-accent-700">View Inventory</span>
              </Link>
              {currentUser?.role === 'admin' && (
                <Link
                  to="/users"
                  className="flex flex-col items-center justify-center p-6 bg-green-50 rounded-lg hover:bg-green-100 transition-colors duration-200"
                >
                  <Users className="w-8 h-8 text-green-600 mb-2" />
                  <span className="text-sm font-medium text-green-700">Manage Users</span>
                </Link>
              )}
              <div className="flex flex-col items-center justify-center p-6 bg-yellow-50 rounded-lg">
                <TrendingUp className="w-8 h-8 text-yellow-600 mb-2" />
                <span className="text-sm font-medium text-yellow-700">View Reports</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Recent Items */}
      <div className="card mt-8">
        <div className="p-6 border-b border-secondary-200">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-semibold text-secondary-900">Recent Items</h2>
            <Link
              to="/inventory"
              className="text-primary-600 hover:text-primary-700 text-sm font-medium"
            >
              View All
            </Link>
          </div>
        </div>
        <div className="p-6">
          <div className="space-y-4">
            {recentItems.map((item) => (
              <div key={item.id} className="flex items-center justify-between p-3 bg-secondary-50 rounded-lg">
                <div className="flex items-center space-x-3">
                  <img
                    src={item.image}
                    alt={item.name}
                    className="w-10 h-10 rounded-lg object-cover"
                  />
                  <div>
                    <p className="font-medium text-secondary-900">{item.name}</p>
                    <p className="text-sm text-secondary-500">{item.sku}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="font-medium text-secondary-900">{item.quantity}</p>
                  <p className={`text-sm ${item.availability ? 'text-green-600' : 'text-red-600'}`}>
                    {item.availability ? 'Available' : 'Out of Stock'}
                  </p>
                  <div className="flex space-x-2">
                    <Link
                      to={`/inventory/${item.id}`}
                      className="flex-1 btn btn-secondary flex items-center justify-center"
                    >
                      <Eye className="w-4 h-4 mr-2" />
                      View
                    </Link>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
